INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Push-Up_Wide','Push-Up Wide','pecho',ARRAY['abdominales','hombros','tríceps'],'peso corporal','strength',ARRAY['With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position.','To begin, allow the elbows to flex, lowering your chest to the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position by extending the elbows. Exhale as you perform this step.','After pausing at the contracted position, repeat the movement for the prescribed amount of repetitions.'],'With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position. To begin, allow the elbows to flex, lowering your chest to the floor as you inhale. Using your pectoral muscles, press your upper body back up to the starting position by extending the elbows. Exhale as you perform this step. After pausing at the contracted position, repeat the movement for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Up_Wide/0.jpg','exercisedb',true),('Push-Ups_-_Close_Triceps_Position','Push-Ups - Close Triceps Position','tríceps',ARRAY['pecho','hombros'],'peso corporal','strength',ARRAY['Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms'''' length.','Lower yourself until your chest almost touches the floor as you inhale.','Using your triceps and some of your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'],'Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms'' length. Lower yourself until your chest almost touches the floor as you inhale. Using your triceps and some of your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step. After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_-_Close_Triceps_Position/0.jpg','exercisedb',true),('Push-Ups_With_Feet_Elevated','Push-Ups With Feet Elevated','pecho',ARRAY['hombros','tríceps'],'peso corporal','strength',ARRAY['Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.','Place your toes on top of a flat bench. This will allow your body to be elevated. Note: The higher the elevation of the flat bench, the higher the resistance of the exercise is.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'],'Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length. Place your toes on top of a flat bench. This will allow your body to be elevated. Note: The higher the elevation of the flat bench, the higher the resistance of the exercise is. Lower yourself until your chest almost touches the floor as you inhale. Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step. After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_Elevated/0.jpg','exercisedb',true),('Push-Ups_With_Feet_On_An_Exercise_Ball','Push-Ups With Feet On An Exercise Ball','pecho',ARRAY['hombros','tríceps'],'pelota de ejercicio','strength',ARRAY['Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.','Place your toes on top of an exercise ball. This will allow your body to be elevated.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'],'Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length. Place your toes on top of an exercise ball. This will allow your body to be elevated. Lower yourself until your chest almost touches the floor as you inhale. Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step. After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_On_An_Exercise_Ball/0.jpg','exercisedb',true),('Push_Press','Push Press','hombros',ARRAY['cuádriceps','tríceps'],'barra','olympic weightlifting',ARRAY[]::text[],NULL,'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press/0.jpg','exercisedb',true),('Push_Press_-_Behind_the_Neck','Push Press - Behind the Neck','hombros',ARRAY['pantorrillas','cuádriceps','tríceps'],'barra','olympic weightlifting',ARRAY['Standing with the weight racked on the back of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, moving the bar in a vertical path.','Using the momentum generated, finish pressing the weight overhead be extending through the arms.','Return to the starting position, using your legs to absorb the impact.'],'Standing with the weight racked on the back of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, moving the bar in a vertical path. Using the momentum generated, finish pressing the weight overhead be extending through the arms. Return to the starting position, using your legs to absorb the impact.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press_-_Behind_the_Neck/0.jpg','exercisedb',true),('Push_Up_to_Side_Plank','Push Up to Side Plank','pecho',ARRAY['abdominales','hombros','tríceps'],'peso corporal','strength',ARRAY['Get into pushup position on the toes with your hands just outside of shoulder width.','Perform a pushup by allowing the elbows to flex. As you descend, keep your body straight.','Do one pushup and as you come up, shift your weight on the left side of the body, twist to the side while bringing the right arm up towards the ceiling in a side plank.','Lower the arm back to the floor for another pushup and then twist to the other side.','Repeat the series, alternating each side, for 10 or more reps.'],'Get into pushup position on the toes with your hands just outside of shoulder width. Perform a pushup by allowing the elbows to flex. As you descend, keep your body straight. Do one pushup and as you come up, shift your weight on the left side of the body, twist to the side while bringing the right arm up towards the ceiling in a side plank. Lower the arm back to the floor for another pushup and then twist to the other side. Repeat the series, alternating each side, for 10 or more reps.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Up_to_Side_Plank/0.jpg','exercisedb',true),('Pushups','Pushups','pecho',ARRAY['hombros','tríceps'],'peso corporal','strength',ARRAY['Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length.','Next, lower yourself downward until your chest almost touches the floor as you inhale.','Now breathe out and press your upper body back up to the starting position while squeezing your chest.','After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed.'],'Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length. Next, lower yourself downward until your chest almost touches the floor as you inhale. Now breathe out and press your upper body back up to the starting position while squeezing your chest. After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups/0.jpg','exercisedb',true),('Pushups_Close_and_Wide_Hand_Positions','Pushups (Close and Wide Hand Positions)','pecho',ARRAY['hombros','tríceps'],'peso corporal','strength',ARRAY['Lie on the floor face down and body straight with your toes on the floor and the hands wider than shoulder width for a wide hand position and closer than shoulder width for a close hand position. Make sure you are holding your torso up at arms length.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'],'Lie on the floor face down and body straight with your toes on the floor and the hands wider than shoulder width for a wide hand position and closer than shoulder width for a close hand position. Make sure you are holding your torso up at arms length. Lower yourself until your chest almost touches the floor as you inhale. Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step. After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups_Close_and_Wide_Hand_Positions/0.jpg','exercisedb',true),('Pyramid','Pyramid','espalda baja',ARRAY['hombros'],'pelota de ejercicio','stretching',ARRAY['Start off by rolling your torso forward onto the ball so your hips rest on top of the ball and become the highest point of your body.','Rest your hands and feet on the floor. Your arms and legs can be slightly bent or straight, depending on the size of the ball, your flexibility, and the length of your limbs. This also helps develop stabilizing strength in your torso and shoulders.'],'Start off by rolling your torso forward onto the ball so your hips rest on top of the ball and become the highest point of your body. Rest your hands and feet on the floor. Your arms and legs can be slightly bent or straight, depending on the size of the ball, your flexibility, and the length of your limbs. This also helps develop stabilizing strength in your torso and shoulders.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pyramid/0.jpg','exercisedb',true);